	if not formation then
		printErrorN("no formation data type "..combatType)
		return
	end
	self._combatType = combatType
	self._formationRefId = formation.formationRefId
	self._grids = formation.grids
	self._teamIndex = formation.teamIndex
	-- 【G公共支持】删除神器功能相关数据
	-- self._artifact = formation.artifactId
	self._treasureSkilIds = formation.treasureSkilIds
	self._divineWeaponStarRefIds = formation.divineWeaponStarRefIds
	-- self._petFights= formation.petFights
	-- self._petHelps = formation.petHelps
	self._isSetFormation = false
	self:RequestSetFormation()
end

function LFightStatement:StartAfterSetFormation(combatData)
	self._combatData = combatData
	self._combatType = combatData.combatType
	self._state = LCombatStateConst.STATE_SET_FORMATION
	self:RequestCombat()
end

function LFightStatement:OnSetFormationResp(pb)
	if self._state ~= LCombatStateConst.STATE_SET_FORMATION then
		return false
	end
	local teamIndexSet = pb.teamIndexSet
	local first = teamIndexSet[1]

	local combatType = first.formationType
	--local teamIndex = first.teamIndex[1]


	--local combatType = pb.formationType
	local reqIndex = pb.reqIndex
	local setType = pb.formationSetType
	if setType == 1 or reqIndex ~= self._formationReqIndex or combatType~=self._combatType then
		return false
	end

	self:RequestCombat()
	return true
end

function LFightStatement:StartTestCombat(combatData)
	self._combatType = combatData.combatType
	self._formationA = combatData.formationA
	self._formationB = combatData.formationB
	self._monsterIdA = combatData.monsterIdA
	self._monsterIdB = combatData.monsterIdB

	self._state = LCombatStateConst.STATE_COMBAT_REQ
	gModelFormation:OnSetTestCombatReq(self._combatType,self._formationA, self._formationB, self._monsterIdA,self._monsterIdB)
end

function LFightStatement:OnTestCombatResp(pb)
	if self._state ~= LCombatStateConst.STATE_COMBAT_REQ then
		return false
	end
	local combatType =  LCombatTypeConst.COMBAT_TEST_BATTLE

	local endExtraData =
	{
		monsterA = pb.mosRefIdA ~= 0 and pb.mosRefIdA or nil,
		monsterB = pb.mosRefIdB ~= 0 and pb.mosRefIdB or nil
	}
	--if pb.monsterRefId and pb.monsterRefId > 0 then
	--	endExtraData.isMonsterTest = true
	--	endExtraData.monsterTestRefId = pb.monsterRefId
	--end


	self:SetReportId(pb.reportId)

	local combatExtraData = {
		combatType = combatType,
		offlineTime = 0,
		isBattleToBackground = false,
		meName = gModelPlayer:GetPlayerName(),
		otherName = gModelPlayer:GetPlayerName(),
		isNew = true,
		skip = true,
		battleEndfun = function()
			gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_TEST_BATTLE,endExtraData)
		end
	}

	self._combatData = combatExtraData

	self._combatRespIsOk = true
	self:CheckStartReqReport()
	return true
end

function LFightStatement:OnBossTowerSetFormationResp()
	if self._state ~= LCombatStateConst.STATE_SET_FORMATION then
		return false
	end
	self:RequestCombat()
	return true
end

function LFightStatement:RequestCombat()
	self._combatData.isNew = true

	self._reportIsOk = false
	self._combatRespIsOk = false
	self._reqTime = self:GetCurTime()
	self._state = LCombatStateConst.STATE_COMBAT_REQ

	if self._combatType == LCombatTypeConst.COMBAT_PK then
		local playerId = self._combatData.playerId
		local serverId = self._combatData.serverId
		local url = self._combatData.url
		if url then
			gModelBattle:OnShareFormationPKReq(url)
		else
			gModelBattle:OnPKReq(playerId,serverId)
		end
	elseif self._combatType == LCombatTypeConst.COMBAT_GUILD_WAR then
		gModelBattle:DestroyBattleStatement(self._combatType)
	elseif self._combatType == LCombatTypeConst.COMBAT_ARENA_DEFEND
			or self._combatType == LCombatTypeConst.COMBAT_ARENA_PEAK_ATTACK
			or self._combatType == LCombatTypeConst.COMBAT_CROSS_SERVER_CHAMPION then
		GF.ShowMessage(ccClientText(10346))
		gModelBattle:DestroyBattleStatement(self._combatType)
	elseif self._combatType == LCombatTypeConst.COMBAT_CROSS_SERVER_LADDER then
		if self._isSetFormation then
			GF.ShowMessage(ccClientText(10346))
			gModelBattle:DestroyBattleStatement(self._combatType)
		else
			self:CombatReqInternal()
			--gModelBattle:OnCombatReq(self._combatData)
		end
	elseif gModelBattle:IsEndlessCombat(self._combatType) then
		local combatData = self._combatData

		if combatData.isFromBuffWnd then
			combatData.isFromBuffWnd = false
			--gModelBattle:OnCombatReq(self._combatData)
			self:CombatReqInternal()
			return
		end

		if combatData.fromPrepare then
			combatData.fromPrepare = false
			GF.OpenWnd("UIUendBfPop",{combatData = combatData,isOne = true})
		else
			--gModelBattle:OnCombatReq(self._combatData)
			self:CombatReqInternal()
		end
	else
		self:CombatReqInternal()
		--gModelBattle:OnCombatReq(self._combatData)
	end

end

---从收到战报id 开始流程 离线战斗等
function LFightStatement:StartFromCombatResp(combatData)
	self._combatType = combatData.combatType
	self._combatData = combatData
	self._state = LCombatStateConst.STATE_COMBAT_REQ
	self._reportIsOk = true
	self:OnCombatResp(combatData)
end

function LFightStatement:StartFromReportId(reportId,combatType,combatData)
	self._combatType = combatType
	self._combatData = combatData
	self._serverId = combatData.serverId

	if string.isempty(reportId) then
		self._isError = true
		printErrorN("report list is empty")
		if combatType then
			gModelBattle:RecordVideoBattleLife(combatType,false)
		end
		return
	end


	self:SetReportId(reportId)

	self:TryRequestWebReport()
end



function LFightStatement:SetReportId(reportId)
	self._reportId = reportId
end

function LFightStatement:OnCombatResp(pb)

	if self._state ~= LCombatStateConst.STATE_COMBAT_REQ then
		return false
	end

	local combatType = pb.combatType
	if self._combatType ~= combatType then
		return false
	end

	if gModelBattle:IsEndlessCombat(combatType) then
		gModelEndles:ClearNewSelectBuff()
	end

	self:SetReportId(pb.reportId)
	self._startTime = tonumber(pb.startTime)
	self._targetName = pb.targetName
	self._targetLevel = pb.targetLevel
	self._monsterId = pb.monsterId
	self._isRepeat = pb.isRepeat
	local serverId = pb.serverId or 0
	printInfoN(string.format("serverId %s ",serverId))
	self._serverId = serverId > 0 and serverId or gLGameLogin:GetActualServerId()


	if gModelBattle:IsEndlessCombat(combatType) then
		local monsterId = self._monsterId
		if monsterId > 0 then
			local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
			self._combatData.otherName = ccLngText(monsterFormationRef.name)
		end
	end

	self._combatData.targetLevel = pb.targetLevel

	self._combatRespIsOk = true

	self:CheckStartReqReport()
	return true
end

function LFightStatement:OnCombatReportOk(pb)
	if not self._reportId then
		self:SetReportId(pb.id)
	end

	printInfoN("report size "..pb.size)

	self._reportIsOk = true

	self:CheckStartReqReport()
	return true
end

function LFightStatement:CheckStartReqReport()

	if not self._combatRespIsOk or not self._reportIsOk then
		return
	end

	self:TryRequestWebReport()
end

function LFightStatement:TryRequestWebReport()
	if self:IsDestroy() then return end
	if self._state >= LCombatStateConst.STATE_REPORT_REQ then
		return
	end

	self._state = LCombatStateConst.STATE_REPORT_REQ
	self._reqTime = self:GetCurTime()
	self:RequestWebReport()
end

function LFightStatement:RequestWebReport()
	local reportId = self._reportId



	local serverId = self._serverId
	if not serverId then
		serverId = gLGameLogin:GetActualServerId()
	end

	local reportInfo =
	{
		reportId = reportId,
		combatType = self._combatType,
		serverId = serverId,
		callback = function(reportTable)
			self:DoRespWebReport(reportTable)
		end
	}

	if not reportInfo.serverId then
		LogError(string.format("report serverId is nil"))
		return
	end


	local getter = self._getter
	if getter then
		getter:Destroy()
	end
	getter = LFightReportGetter:New()
	self._getter = getter
	getter:Start(reportInfo)



end

function LFightStatement:GetSid()
	return self._sid
end

function LFightStatement:IsBossTower()
	return self._isBossTowerCombat
end

function LFightStatement:DoRespWebReport(reportTable)
	if not gLFightManager then
		return
	end
	local combatType = self._combatType
	self._combatData.resultKey = self._reportId
	gLFightManager:StartBattle(self._reportId, combatType, self._combatData, reportTable)
end

function LFightStatement:BattleFinish()
	printInfoN("BattleFinish combatType "..tostring(self._combatType))
	self._state = LCombatStateConst.STATE_COMBAT_FINISHED

	if not self._combatData then
		return
	end
	local endFunc = self._combatData.endFunc
	if endFunc then
		endFunc()
	end
end

function LFightStatement:OnReqCombatResult()
	self._isWaitResult = true
end

function LFightStatement:OnRespCombatResult()
	self._isWaitResult = false
end

function LFightStatement:CheckResendReqResult()
    if self._isWaitResult then
        gModelBattle:OnCombatResultReq(self._reportId,self._combatType)
    end
end

function LFightStatement:CombatReqInternal()
	self:OnReqCombat()
	gModelBattle:OnCombatReq(self._combatData)
end

function LFightStatement:OnReqCombat()
	self._isWaitCombatResp = true
end

function LFightStatement:OnRespCombat()
	self._isWaitCombatResp = false
end

---重发
function LFightStatement:CheckResendReqCombat()
	if self._isWaitCombatResp then
		gModelBattle:OnCombatReq(self._combatData)
	end
end


-----------------------------------------------------------------
function LFightStatement:IsDestroy()
	return self._isDestroy
end

function LFightStatement:Destroy()

	if self._timer  then
		self._timer:Destroy()
		self._timer = nil
	end

	if self._getter then
		self._getter:Destroy()
		self._getter = nil
	end

	table.removeall(self)
	self._isDestroy = true
end
------------------------------------------------------------------

return LFightStatement